// GetTableName return the associated db table name.
func (r *TOrder) GetTableName() string {
	var viewNamePattern = regexp.MustCompile(`(?i)^t_v_[a-z0-9_]+$`)
	tableName := "t_order"
	if viewNamePattern.MatchString(tableName) {
		return tableName[2:]
	}
	return tableName
}

